import{_ as e,c as a,o as t,aj as o}from"./chunks/framework.CLcCQpUA.js";const m=JSON.parse('{"title":"📒 额外使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"faq/extra.md","filePath":"faq/extra.md"}'),c={name:"faq/extra.md"},d=o('<h1 id="📒-额外使用说明" tabindex="-1">📒 额外使用说明 <a class="header-anchor" href="#📒-额外使用说明" aria-label="Permalink to &quot;📒 额外使用说明&quot;">​</a></h1><h2 id="_1-配置生效相关" tabindex="-1">1. 配置生效相关 <a class="header-anchor" href="#_1-配置生效相关" aria-label="Permalink to &quot;1. 配置生效相关&quot;">​</a></h2><p>除少部分条目例如预设(只影响gui)，能当即保存时立即生效(保存配置的操作与gui同一进程);<br> 其余影响后台进程的配置条目在选择网站后定型(点选网站后<code>后台进程</code>即开始)，<br> 如果选网站后才反应过来改配置，需重启CGS方可生效</p><h2 id="_2-域名相关" tabindex="-1">2. 域名相关 <a class="header-anchor" href="#_2-域名相关" aria-label="Permalink to &quot;2. 域名相关&quot;">​</a></h2><p>各网站的 <code>发布页</code>/<code>永久链接</code> 能在 <code>scripts/utils/website/__init__.py</code> 里找到<br> （国内域名专用）域名缓存文件为 <code>scripts/__temp/xxx_domain.txt</code>（xxx = <code>wnacg</code>或<code>jm</code>），<br> 再开程序会检测修改时间大于24小时则失效重新获取，处于24小时内则可对此文件删改或加个空格保存即时生效</p><div class="info custom-block github-alert"><p class="custom-block-title">手动改域名缓存文件示例</p><p>wnacg_domain.txt，没有则自建，内容填个 <code>www.wn01.uk</code> 即可</p></div><blockquote><p><code>发布页</code>/<code>永久链接</code>失效的情况下鼓励用户向开发者提供新可用网址，让软件能够持续使用</p></blockquote>',7),r=[d];function i(s,_,n,l,p,h){return t(),a("div",null,r)}const x=e(c,[["render",i]]);export{m as __pageData,x as default};
